#include <iostream>
#include <ctime>     // For time() 
using namespace std;  
void logError(const char* errorMessage) {   
	time_t result = time(0);     
	cout << "[ "<< ctime(&result ) <<" ] Error: " <<  errorMessage  << endl ;      
}     // End of function